class RateLimitInterceptor(ServerInterceptor):
    """Simple rate limiting interceptor."""

    def __init__(self, max_requests_per_second: int = 100):
        self._max_rps = max_requests_per_second
        self._request_counts = {}
        self._window_start = time.time()

    def intercept_service(self, continuation, handler_call_details):
        method = handler_call_details.method
        current_time = time.time()

        # Reset window every second
        if current_time - self._window_start >= 1.0:
            self._request_counts.clear()
            self._window_start = current_time

        count = self._request_counts.get(method, 0)
        if count >= self._max_rps:
            logger.warning(f"Rate limit exceeded for {method}")

            def abort(request, context):
                context.abort(
                    grpc.StatusCode.RESOURCE_EXHAUSTED,
                    "Rate limit exceeded"
                )

            return grpc.unary_unary_rpc_method_handler(abort)

        self._request_counts[method] = count + 1
        return continuation(handler_call_details)


